-- 改变cover_image_url列的类型为MEDIUMTEXT以能够存储Base64编码图片
ALTER TABLE landmark MODIFY COLUMN cover_image_url MEDIUMTEXT;

-- 更新地标的封面图数据为内嵌式Base64编码数据，实现免外网依赖与高迁移性

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L01';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L04';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L05';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L06';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L08';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L09';

UPDATE landmark SET cover_image_url = 'data:image/jpeg;base64,' WHERE code = 'L10';
